Problem 6: Summaries (Year + Coverage)

all_data_summary &lt;- temperatures_clean |&gt;
  left_join(countries_clean, by = "FIPS 10-4")

summary_year &lt;- all_data_summary |&gt;
  group_by(Year) |&gt;
  summarize(
    mean_temp = mean(AvgTemp, na.rm = TRUE),
    min_temp  = min(AvgTemp,  na.rm = TRUE),
    max_temp  = max(AvgTemp,  na.rm = TRUE),
    .groups = "drop"
  ) |&gt;
  arrange(Year)

coverage_year &lt;- all_data_summary |&gt;
  group_by(Year) |&gt;
  summarize(
    n_measurements = n(),
    .groups = "drop"
  ) |&gt;
  arrange(Year)

coverage_country &lt;- all_data_summary |&gt;
  group_by(Name) |&gt;
  summarize(
    n_measurements = n(),
    .groups = "drop"
  ) |&gt;
  arrange(desc(n_measurements))

coverage_year |&gt;
  filter(Year == 2025)

